import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication และ Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Safety/authentication-and-login-devices.md","filePath":"th-TH/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"th-TH/Safety/authentication-and-login-devices.md"};function r(c,e,p,u,h,m){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="authentication-และ-login-device-management" tabindex="-1">Authentication และ Login Device Management <a class="header-anchor" href="#authentication-และ-login-device-management" aria-label="Permalink to &quot;Authentication และ Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> และ <code>Login Device Management</code> ใช้ปกป้อง ImgBed admin panel, public upload entry และ WebDAV access</p><p>หน้านี้ใช้ตั้งค่า access credentials, ตรวจดู devices ที่ sign in อยู่ และ revoke sessions เก่าหากจำเป็น</p><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>เปิด admin panel แล้วไปที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>หน้านี้มีสองส่วนหลัก:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-ทําอะไร" tabindex="-1">Authentication Management ทำอะไร <a class="header-anchor" href="#authentication-management-ทําอะไร" aria-label="Permalink to &quot;Authentication Management ทำอะไร&quot;">​</a></h2><p>Authentication Management เก็บ access credentials</p><p>มีสองประเภท:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication คือ upload password</p><p>เมื่อกำหนด upload password แล้ว visitors ทั่วไปต้องใส่ password ก่อนใช้ upload page เหมาะเมื่อไม่ต้องการเปิด public upload page ให้ทุกคนใช้งานได้ทันที</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="ตั้งค่า-upload-password" tabindex="-1">ตั้งค่า Upload Password <a class="header-anchor" href="#ตั้งค่า-upload-password" aria-label="Permalink to &quot;ตั้งค่า Upload Password&quot;">​</a></h3><p>เมื่อ configure upload password แล้ว:</p><ul><li>Visitors ต้องใส่ password ก่อนใช้ upload page</li><li>จะ upload ได้หลังจาก password ถูกต้องเท่านั้น</li><li>ถ้าเปิด user-side device sessions ไว้ ImgBed จะบันทึก user-side device นั้น</li></ul><p>การเปลี่ยน upload password จะทำให้ user-side sessions เก่า invalid Visitors ต้องใส่ password ใหม่อีกครั้ง</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication ใช้ admin username และ password</p><p>ส่วนนี้ปกป้อง admin panel สำหรับ production use ควร configure ไว้เสมอ</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="ตั้งค่า-admin-credentials" tabindex="-1">ตั้งค่า Admin Credentials <a class="header-anchor" href="#ตั้งค่า-admin-credentials" aria-label="Permalink to &quot;ตั้งค่า Admin Credentials&quot;">​</a></h3><p>เมื่อ configure admin username และ password แล้ว:</p><ul><li>ต้อง login ก่อนเปิด admin panel</li><li>Login สำเร็จแล้วจะสร้าง admin device record</li><li>ใน Login Device Management สามารถ review, clean up หรือ force devices offline ได้</li></ul><p>การเปลี่ยน admin username หรือ password จะทำให้ admin sessions เก่า invalid ต้อง sign in ใหม่</p><h2 id="login-device-management-ทําอะไร" tabindex="-1">Login Device Management ทำอะไร <a class="header-anchor" href="#login-device-management-ทําอะไร" aria-label="Permalink to &quot;Login Device Management ทำอะไร&quot;">​</a></h2><p>Login Device Management แสดง devices ที่เคย sign in</p><p>ช่วยตรวจได้ว่า:</p><ul><li>Devices ใด access admin panel</li><li>Devices ใด access user-side upload page</li><li>WebDAV clients ใด connected</li><li>Device session ยัง valid อยู่หรือไม่</li><li>ควร force offline devices เก่าหรือไม่</li></ul><p>Page มีสาม tabs:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>ด้านบนของ Login Device Management สามารถ configure global cookie behavior ได้</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>ควบคุมว่า user-side login จะ active ได้นานกี่วัน</p><p>เช่น ตั้งเป็น 14 days โดยปกติ visitors ไม่ต้องใส่ upload password ซ้ำภายใน 14 วัน</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>ควบคุมว่า admin login จะ active ได้นานกี่วัน</p><p>เช่น ตั้งเป็น 14 days โดยปกติ administrators ไม่ต้อง sign in ซ้ำภายใน 14 วัน</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>เมื่อเปิด Secure mode browsers จะส่ง login cookies ผ่าน HTTPS เท่านั้น</p><p>ควร enable สำหรับ production HTTPS sites ห้ามเปิดตอน local HTTP testing ไม่เช่นนั้นอาจเจออาการ &quot;login สำเร็จ แต่ refresh แล้วหลุดออก&quot;</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab แสดง devices ที่ sign in เข้า admin panel</p><p>Device records จะแสดงเมื่อ configure admin credentials แล้ว และเข้าถึง admin panel ผ่าน login</p><p>แต่ละ device card อาจแสดง:</p><ul><li>Device และ browser information</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>ถ้าเห็น device ที่ไม่รู้จัก ให้ใช้ <code>Force Offline</code> เพื่อทำให้ invalid</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> ลบ login records เก่าใน tab ปัจจุบันแบบ bulk</p><p>ใช้เมื่อสงสัยว่า sessions เก่าอาจยัง active อยู่บน devices อื่น</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> ทำให้ device session หนึ่ง invalid</p><p>หลัง force offline แล้ว:</p><ul><li>Admin devices ต้อง sign in ใหม่</li><li>User-side devices ต้องใส่ upload password ใหม่</li><li>WebDAV clients ต้อง authenticate ใหม่</li></ul><p>Expired หรือ invalid devices สามารถลบได้เช่นกัน</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>Current device card จะถูก mark เป็น <code>Current Device</code></p><p>หลัง sign out current device:</p><ul><li>Current admin session จะ sign out</li><li>Current user-side session จะ sign out</li></ul><p>ต้อง sign in ใหม่ก่อนใช้งานส่วนนั้นต่อ</p>',65)])])}const b=t(d,[["render",r]]);export{f as __pageData,b as default};
